package com.google.gson.stream;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonWriterTest {
  private JsonWriter jsonWriter;
  private StringWriter stringWriter;

  private Method writeDeferredNameMethod;
  private Method beforeNameMethod;
  private Method stringMethod;

  @BeforeEach
  public void setUp() throws NoSuchMethodException {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);

    writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);

    beforeNameMethod = JsonWriter.class.getDeclaredMethod("beforeName");
    beforeNameMethod.setAccessible(true);

    stringMethod = JsonWriter.class.getDeclaredMethod("string", String.class);
    stringMethod.setAccessible(true);
  }

  @Test
  public void testWriteDeferredName_NullDeferredName() throws Throwable {
    // deferredName is null by default, so writeDeferredName should do nothing
    // Invoke private method
    writeDeferredNameMethod.invoke(jsonWriter);
    // No exception and no output expected
    assertEquals("", stringWriter.toString());
  }

  @Test
  public void testWriteDeferredName_WithDeferredName() throws Throwable {
    // Set deferredName via reflection
    setDeferredName(jsonWriter, "testName");

    // Spy on jsonWriter to verify calls to beforeName() and string()
    JsonWriter spyWriter = spy(jsonWriter);

    // Replace deferredName field in spyWriter
    setDeferredName(spyWriter, "testName");

    // Invoke private writeDeferredName on spyWriter
    writeDeferredNameMethod.invoke(spyWriter);

    // Verify beforeName() and string(String) called once each with expected argument
    verify(spyWriter, times(1)).beforeName();
    verify(spyWriter, times(1)).string("testName");

    // Verify deferredName is cleared
    assertNull(getDeferredName(spyWriter));
  }

  private void setDeferredName(JsonWriter writer, String value) throws Exception {
    var field = JsonWriter.class.getDeclaredField("deferredName");
    field.setAccessible(true);
    field.set(writer, value);
  }

  private String getDeferredName(JsonWriter writer) throws Exception {
    var field = JsonWriter.class.getDeclaredField("deferredName");
    field.setAccessible(true);
    return (String) field.get(writer);
  }
}
